  ('judicial-0b5ab5d8-moex-00032', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-113-57eacf76', 'sub-judicial-0b5ab5d8-03', NULL, 'essay', '債權人甲向法院聲請對債務人乙之財產強制執行，執行法院製作分配
表，定於民國（下同）112 年 9月 3 日實行分配，並於同年 7 月29 日通
知甲、乙及併案債權人丙。甲於同年 8 月24 日具狀聲明異議，並表明丙
之債權不存在，應自分配表中剔除。嗣分配期日無人到場，執行法院未
更正分配表，亦未將甲之聲明異議狀通知乙及丙。甲於同年 9 月 23 日
提起分配表異議之訴，於同月 24日向執行法院為起訴之證明。甲之起訴
是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:04+00:00", "source_pdf_sha1": "0925a22e5476", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "107", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
